#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Structure to represent a queue node
typedef struct Node {
    int vertex;
    struct Node* next;
} Node;

// Structure to represent a queue
typedef struct Queue {
    Node* front;
    Node* rear;
} Queue;

// Function to create a new queue node
Node* createNode(int vertex) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next = NULL;
    return newNode;
}

// Function to create a queue
Queue* createQueue() {
    Queue* q = (Queue*) malloc(sizeof(Queue));
    if (!q) {
        printf("Memory error
");
        return NULL;
    }
    q->front = q->rear = NULL;
    return q;
}

// Function to check if the queue is empty
int isEmpty(Queue* q) {
    return (q->front == NULL);
}

// Function to add an item to the queue
void enqueue(Queue* q, int vertex) {
    Node* newNode = createNode(vertex);
    if (q->rear) {
        q->rear->next = newNode;
        q->rear = newNode;
    } else {
        q->front = q->rear = newNode;
    }
}

// Function to remove an item from the queue
int dequeue(Queue* q) {
    if (isEmpty(q)) {
        return -1;
    }
    Node* temp = q->front;
    int vertex = temp->vertex;
    q->front = temp->next;
    if (q->front == NULL) {
        q->rear = NULL;
    }
    free(temp);
    return vertex;
}

// Function to find the shortest path using BFS
void shortestPath(int** edges, int N, int M, int src) {
    // Create an adjacency list of size N to store the undirected graph
    int** adj = (int**) malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        adj[i] = (int*) malloc(2 * sizeof(int));
        adj[i][0] = 0;
        adj[i][1] = 0;
    }

    // Build the graph by adding edges to the adjacency list
    for (int i = 0; i < M; i++) {
        int u = edges[i][0];
        int v = edges[i][1];
        adj[u][0]++;
        adj[u][1] = v;
        adj[v][0]++;
        adj[v][1] = u;
    }

    // Initialize the distance array with a large value (treated as infinity)
    int* dist = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        dist[i] = INT_MAX;
    }

    // Set the source node distance to 0
    dist[src] = 0;

    // Use a queue to perform BFS traversal
    Queue* q = createQueue();
    enqueue(q, src);

    // Loop until queue is empty
    while (!isEmpty(q)) {
        int node = dequeue(q);

        // Traverse all adjacent nodes
        for (int i = 0; i < adj[node][0]; i++) {
            int neighbor = adj[node][1];
            if (dist[node] + 1 < dist[neighbor]) {
                dist[neighbor] = dist[node] + 1;
                enqueue(q, neighbor);
            }
        }
    }

    // Print the shortest distances from source to each node
    for (int i = 0; i < N; i++) {
        if (dist[i] == INT_MAX) {
            printf("-1 ");
        } else {
            printf("%d ", dist[i]);
        }
    }
    printf("\n");
}

